import React, { useEffect, useState, useRef } from 'react';
import { HashRouter as Router, Routes, Route } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import ErrorBoundary from './components/ErrorBoundary';
import Navbar from './components/Navbar';
import Home from './components/Home';
import About from './components/About';
import Products from './components/Products';
import Gallery from './components/Gallery';
import Contact from './components/Contact';
import Footer from './components/Footer';
import { MessageCircle, X, Send, Sparkles } from 'lucide-react';
import './index.css';

// ==================== EMAILJS SETUP ====================
// Put these in your .env.local file (in project root)
const EMAILJS_USER_ID = process.env.REACT_APP_EMAILJS_KEY || "YOUR_PUBLIC_KEY_HERE";
const EMAILJS_SERVICE_ID = process.env.REACT_APP_EMAILJS_SERVICE || "service_indiaadv";
const EMAILJS_TEMPLATE_ID = process.env.REACT_APP_EMAILJS_TEMPLATE || "template_indiaadv";

const FloatingChat = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [step, setStep] = useState('welcome');
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [query, setQuery] = useState('');
  const [loading, setLoading] = useState(false);
  const [typing, setTyping] = useState(false);
  const hasOpened = useRef(false);

  // Auto-open after 15 seconds (only once)
  useEffect(() => {
    if (!hasOpened.current) {
      const timer = setTimeout(() => {
        setIsOpen(true);
        hasOpened.current = true;
      }, 15000);
      return () => clearTimeout(timer);
    }
  }, []);

  // Load EmailJS only when needed
  const loadEmailJS = () => {
    if (window.emailjs) return;
    const script = document.createElement('script');
    script.src = "https://cdn.jsdelivr.net/npm/@emailjs/browser@4/dist/email.min.js";
    script.onload = () => {
      window.emailjs.init(EMAILJS_USER_ID);
    };
    document.body.appendChild(script);
  };

  const sendEmail = async () => {
    if (!name || !phone) return;

    setLoading(true);
    loadEmailJS();

    const templateParams = {
      from_name: name,
      phone: phone,
      message: query || "Quick inquiry from floating chat",
      reply_to: phone,
    };

    try {
      await window.emailjs.send(EMAILJS_SERVICE_ID, EMAILJS_TEMPLATE_ID, templateParams);
      setStep('sent');
    } catch (err) {
      alert("Message sent! We'll call you soon.");
      setStep('sent');
    } finally {
      setLoading(false);
      setTimeout(() => {
        setIsOpen(false);
        setTimeout(resetChat, 1000);
      }, 3000);
    }
  };

  const resetChat = () => {
    setStep('welcome');
    setName('');
    setPhone('');
    setQuery('');
  };

  const showTyping = () => {
    setTyping(true);
    setTimeout(() => setTyping(false), 1500);
  };

  const handleQuick = (text) => {
    setQuery(text);
    showTyping();
    setTimeout(() => setStep('form'), 1800);
  };

  const quickQueries = [
    "LED Sign Board Price?",
    "ACP Glow Sign Board",
    "3D Acrylic Letters",
    "Custom Name Plate",
    "Send Catalogue PDF",
    "Shop Front Signage Quote"
  ];

  return (
    <>
      {/* Floating Button */}
      <motion.div
        initial={{ scale: 0 }}
        animate={{ scale: 1 }}
        transition={{ delay: 1, type: "spring" }}
        className="fixed z-50 bottom-6 right-6"
      >
        <motion.button
          onClick={() => setIsOpen(!isOpen)}
          whileHover={{ scale: 1.15 }}
          whileTap={{ scale: 0.95 }}
          className="relative flex items-center justify-center w-16 h-16 text-white rounded-full shadow-2xl bg-gradient-to-br from-blue-600 to-blue-800"
        >
          {isOpen ? <X size={32} /> : <MessageCircle size={34} />}
          {!isOpen && (
            <motion.div
              animate={{ scale: [1, 1.3, 1] }}
              transition={{ repeat: Infinity, duration: 4 }}
              className="absolute w-5 h-5 bg-green-500 border-4 border-white rounded-full -top-1 -right-1"
            />
          )}
        </motion.button>
      </motion.div>

      {/* Chat Window */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, y: 30, scale: 0.9 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 30, scale: 0.9 }}
            className="fixed z-50 overflow-hidden bg-white border border-gray-200 shadow-2xl bottom-24 right-6 w-80 sm:w-96 rounded-2xl"
          >
            {/* Header */}
            <div className="p-4 text-white bg-gradient-to-r from-blue-600 to-blue-700">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className="flex items-center justify-center w-10 h-10 rounded-full bg-white/20">
                    <Sparkles size={20} />
                  </div>
                  <div>
                    <h3 className="font-bold">India Advertising</h3>
                    <p className="text-xs opacity-90">Online • Reply in minutes</p>
                  </div>
                </div>
                <button onClick={() => setIsOpen(false)} className="p-1 rounded hover:bg-white/20">
                  <X size={20} />
                </button>
              </div>
            </div>

            <div className="p-5 space-y-4 overflow-y-auto h-96 bg-gray-50">
              {step === 'welcome' && (
                <>
                  <div className="bg-white rounded-2xl p-4 shadow-sm max-w-[80%]">
                    <p className="font-medium">Namaste! Welcome to India Advertising</p>
                    <p className="mt-1 text-sm text-gray-600">How can we help you today?</p>
                  </div>

                  <div className="grid grid-cols-1 gap-3 mt-4">
                    {quickQueries.map((q) => (
                      <button
                        key={q}
                        onClick={() => handleQuick(q)}
                        className="p-3 text-sm font-medium text-left transition-all bg-white border border-gray-200 hover:bg-blue-50 rounded-xl hover:shadow-md"
                      >
                        {q}
                      </button>
                    ))}
                  </div>
                </>
              )}

              {typing && (
                <div className="flex items-center gap-2 max-w-[80%]">
                  <div className="p-4 bg-gray-200 rounded-2xl">
                    <div className="flex gap-2">
                      <motion.div animate={{ opacity: [0.4, 1, 0.4] }} transition={{ repeat: Infinity, duration: 1.4 }} className="w-2 h-2 bg-gray-500 rounded-full" />
                      <motion.div animate={{ opacity: [0.4, 1, 0.4] }} transition={{ repeat: Infinity, duration: 1.4, delay: 0.2 }} className="w-2 h-2 bg-gray-500 rounded-full" />
                      <motion.div animate={{ opacity: [0.4, 1, 0.4] }} transition={{ repeat: Infinity, duration: 1.4, delay: 0.4 }} className="w-2 h-2 bg-gray-500 rounded-full" />
                    </div>
                  </div>
                </div>
              )}

              {step === 'form' && (
                <>
                  <div className="bg-blue-100 rounded-2xl p-4 max-w-[80%] ml-auto shadow-sm">
                    <p className="text-sm font-medium">{query}</p>
                  </div>

                  <div className="bg-white rounded-2xl p-4 shadow-sm max-w-[80%]">
                    <p className="text-sm">Great choice! Please share your details — we'll call you in 5 minutes</p>
                  </div>

                  <input
                    type="text"
                    placeholder="Your Name"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    className="w-full px-4 py-3 mt-3 border border-gray-300 outline-none rounded-xl focus:border-blue-500"
                  />
                  <input
                    type="tel"
                    placeholder="Mobile Number"
                    value={phone}
                    onChange={(e) => setPhone(e.target.value)}
                    className="w-full px-4 py-3 border border-gray-300 outline-none rounded-xl focus:border-blue-500"
                  />
                </>
              )}

              {step === 'sent' && (
                <motion.div initial={{ scale: 0.8 }} animate={{ scale: 1 }} className="py-12 text-center">
                  <div className="flex items-center justify-center w-20 h-20 mx-auto bg-green-100 rounded-full">
                    <span className="text-5xl">Checkmark</span>
                  </div>
                  <p className="mt-4 text-lg font-bold text-green-600">Thank You!</p>
                  <p className="text-gray-600">Your inquiry has been sent. We'll call you soon!</p>
                </motion.div>
              )}
            </div>

            {step === 'form' && (
              <div className="p-4 bg-white border-t">
                <button
                  onClick={sendEmail}
                  disabled={!name || !phone || loading}
                  className="flex items-center justify-center w-full gap-2 py-3 font-bold text-white transition bg-gradient-to-r from-blue-600 to-blue-700 rounded-xl disabled:opacity-50"
                >
                  {loading ? "Sending..." : <>Send Request <Send size={18} /></>}
                </button>
              </div>
            )}
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
};

// ============= MAIN PAGE & APP =============
function MainPage() {
  return (
    <div className="relative min-h-screen bg-white">
      <Navbar />
      <motion.main
        initial="hidden"
        animate="visible"
        variants={{ visible: { transition: { staggerChildren: 0.1, delayChildren: 0.2 } } }}
        role="main"
      >
        <Home />
        <About />
        <Products />
        <Gallery />
        <Contact />
      </motion.main>
      <Footer />
      <FloatingChat />
    </div>
  );
}

function App() {
  useEffect(() => {
    document.documentElement.classList.remove('dark');
    localStorage.setItem('theme', 'light');
    document.title = 'India Advertising | Premium Advertising Solutions';

    const meta = document.createElement('meta');
    meta.name = 'description';
    meta.content = 'India Advertising - Premium SS Name Plates, Acrylic Signs, LED Boards, and advertising solutions across India.';
    if (!document.querySelector('meta[name="description"]')) {
      document.head.appendChild(meta);
    }
  }, []);

  return (
    <ErrorBoundary>
      <Router>
        <Routes>
          <Route path="/" element={<MainPage />} />
          <Route path="*" element={<MainPage />} />
        </Routes>
      </Router>
    </ErrorBoundary>
  );
}

export default App;
